final:
module RefModule (
    input wire [3:0] data_in, // 4 input data lines
    input wire [1:0] sel,     // 2-bit select line
    output wire data_out       // output data line
);
    wire __sel_tmp = (sel == 2'b00);
    assign data_out = __sel_tmp ? data_in[0] : (sel == 2'b01) ? data_in[1] :
                      (sel == 2'b10) ? data_in[2] :
                                       data_in[3]; // sel == 2'b11
endmodule
